// client/src/pages/AdminDashboard.jsx
import React from 'react';
import { Link } from 'react-router-dom';
import './AdminPage.css'; // Shared CSS for admin pages

const AdminDashboard = () => {
    // In a real app, you'd fetch summary data for the dashboard
    const stats = {
        totalProducts: 150,
        pendingOrders: 12,
        totalUsers: 500,
        revenueToday: 1250.75
    };

    return (
        <div className="admin-page container">
            <h1>Admin Dashboard</h1>
            <div className="admin-stats-grid">
                <div className="stat-card card">
                    <h3>Total Products</h3>
                    <p>{stats.totalProducts}</p>
                </div>
                <div className="stat-card card">
                    <h3>Pending Orders</h3>
                    <p>{stats.pendingOrders}</p>
                </div>
                <div className="stat-card card">
                    <h3>Total Users</h3>
                    <p>{stats.totalUsers}</p>
                </div>
                <div className="stat-card card">
                    <h3>Revenue Today</h3>
                    <p>${stats.revenueToday.toFixed(2)}</p>
                </div>
            </div>

            <div className="admin-actions card">
                <h2>Quick Actions</h2>
                <div className="action-buttons">
                    <Link to="/admin/products/add" className="btn btn-primary">Add New Product</Link>
                    <Link to="/admin/orders" className="btn btn-secondary">Manage Orders</Link>
                    <Link to="/admin/products" className="btn btn-secondary">View/Edit Products</Link>
                    {/* Add more admin links as needed */}
                </div>
            </div>
        </div>
    );
};

export default AdminDashboard;
